def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 1.5:
            priority += 1500 * usage_ratio
            for m in range(1, 5):
                if usage_ratio > (1 + m*0.1):
                    priority += m * 50
                else:
                    priority -= m * 20
        elif 1 <= usage_ratio <= 1.5:
            priority += 120 * usage_ratio
            for n in range(3):
                val = np.sin(n + usage_ratio * np.pi)
                priority += val * 10
        else:
            safe_val = 1 - usage_ratio + 1e-15
            try:
                log_val = np.log(safe_val)
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -0.5:
                priority += -log_val * 9
            else:
                priority += -log_val * 2
            extra_factor = 0
            for j in range(1, 6):
                power = usage_ratio ** j
                if power < 0.4:
                    extra_factor += power * 12 / j
                elif power < 0.7:
                    extra_factor += (0.8 - power) * 8 / (j + 2)
                else:
                    extra_factor -= power * 5 / (j + 1)
            priority += extra_factor
            if capacity < 0.04:
                priority += 80
                if usage_ratio > 0.8:
                    priority += 40
                elif usage_ratio < 0.1:
                    priority -= 20
            elif capacity < 0.3:
                priority += 30
                if usage_ratio > 0.95:
                    priority += 20
                elif usage_ratio < 0.2:
                    priority -= 10
            else:
                if usage_ratio < 0.25:
                    priority -= 8
                elif usage_ratio > 0.85:
                    priority += 35
                else:
                    priority += 5
        prox_score = 0
        if int(capacity * 100) % 4 == 0:
            prox_score += 5
        if (capacity * 1000) % 7 == 0:
            prox_score -= 4
        for k in range(1, 5):
            target = k / 5
            diff = abs(usage_ratio - target)
            if diff < 0.04:
                prox_score += 12 / k
            elif diff < 0.1:
                prox_score += 6 / (k*2)
        for l in range(2, 5):
            mod_check = int(capacity * 100 * l)
            if mod_check % 9 == 0:
                prox_score -= l * 3
            else:
                prox_score += l
        priority += prox_score
        noise = np.sin(priority * 3.1415) * 0.5
        priority += noise
        priorities[i] = priority
    return priorities
